        while (num > 0) {
            res += num and 1L
            num shr= 1
        }
        return res
    }

    fun dfs(x: Long, depth: Int): Long {
        if (x > n) return 0L
        if (x == 1L) return if (depth == k) 1L else 0L
        if (memo.containsKey(x)) return memo[x]!!

        val next = popcount(x)
        val res = dfs(next, depth + 1)
        memo[x] = res
        return res
