fun solve(n: Long, k: Long): Long {
    // Precompute the popcount-depth for numbers up to 63 bits
    // Since k can be at most 5, we only need to compute up to depth 5
    val depthMap = mutableMapOf<Long, Int>()

    // Function to calculate the popcount-depth of a number
    fun getDepth(x: Long): Int {
        var current = x
        var depth = 0
        while (current != 1L) {
            current = current.bitCount()
            depth++
            if (depth > 5) return -1 // If depth exceeds 5, it's not relevant for our problem
        }
        return depth
    }

    // Precompute the depth for all numbers up to 63 bits
    for (i in 1..(1 shl 63)) {
        depthMap[i] = getDepth(i)
    }

    // Count numbers in [1, n] with exactly k depth
    var count = 0L
    for (i in 1..n) {
        if (depthMap[i] == k) {
            count++
        }
    }

    return count
}
